Based on the reference materials and detailed specifications, here's the complete implementation for the requested functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <type_traits>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Map table names to corresponding C++ structs
  std::map<std::string, rfl::TupleType> table_map = {
    {"Student", rfl::tuple_type_t<Student>()},
    {"Course", rfl::tuple_type_t<Course>()},
    {"Score", rfl::tuple_type_t<Score>()},
    {"Major", rfl::tuple_type_t<Major>()}
  };

  // Get the appropriate type based on table name
  using RecordType = std::remove_cvref_t<decltype(table_map[table_name])>;

  // Connect to database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Create insert statement and insert records
  auto insert_stmt = transpilation::to_insert_or_write<RecordType, dynamic::Insert>(false);
  conn.insert(insert_stmt, records.begin(), records.end()).value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Map table names to primary key column names
  std::map<std::string, std::string> pk_map = {
    {"Student", "SNo"},
    {"Course", "CID"},
    {"Score", "ScID"},
    {"Major", "MID"}
  };

  // Connect to database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Create delete statement with where condition
  auto delete_stmt = dynamic::DeleteFrom{
    .table = table_name,
    .where = dynamic::Condition{
      "pk"_c == record_id  // Assuming primary keys are strings for simplicity
    }
  };

  conn.execute(conn.to_sql(delete_stmt)).value();
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const std::string& new_value) {
  // Map table names to corresponding C++ structs
  std::map<std::string, rfl::TupleType> table_map = {
    {"Student", rfl::tuple_type_t<Student>()},
    {"Course", rfl::tuple_type_t<Course>()},
    {"Score", rfl::tuple_type_t<Score>()},
    {"Major", rfl::tuple_type_t<Major>()}
  };

  // Get the appropriate type based on table name
  using RecordType = std::remove_cvref_t<decltype(table_map[table_name])>;

  // Connect to database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Create update statement
  auto update_stmt = dynamic::Update{
    .table = table_name,
    .set = {col_name: new_value},
    .where = dynamic::Condition{
      "pk"_c == record_id  // Assuming primary keys are strings for simplicity
    }
  };

  conn.execute(conn.to_sql(update_stmt)).value();
}
```

**Key Implementation Details:**

1. **Table-Type Mapping**: Uses `rfl::tuple_type_t` to map table names to their corresponding C++ struct types for type-safe operations.

2. **Database Connection**: Uses `sqlgen::sqlite::connect()` with the predefined `db_path` to establish connection.

3. **Insert Operation**: 
   - Uses `transpilation::to_insert_or_write()` to generate proper INSERT statement
   - Calls `conn.insert()` with the generated statement and record iterators

4. **Delete Operation**:
   - Constructs `dynamic::DeleteFrom` statement with WHERE clause
   - Uses `conn.to_sql()` to convert dynamic statement to SQL
   - Executes using `conn.execute()`

5. **Update Operation**:
   - Constructs `dynamic::Update` statement with SET and WHERE clauses
   - Uses `conn.to_sql()` for conversion and `conn.execute()` for execution

6. **Primary Key Handling**: Assumes primary keys are strings for simplicity, but in practice would need type mapping based on the actual table schema.

**Note**: This implementation makes some simplifying assumptions about primary key types and column names. In a production scenario, you would need to implement proper type mapping and error handling for different data types and primary key variations.

