Based on the reference materials and detailed specifications, here's the complete implementation of the `analyze_social_network` function using sqlgen:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
  int mutual_count;
};

std::vector<FriendConnection> analyze_social_network_impl() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables
  auto create_user = drop<User> | if_exists | create_table<User>;
  auto create_friendship = drop<Friendship> | if_exists | create_table<Friendship>;

  // Execute table creation
  create_user(conn);
  create_friendship(conn);

  // Query 1: Mutual friends using SELF-JOIN
  auto mutual_query = select_from<User, "u1"_t1>(
      "username"_t1 | as<"user1_name">,
      "username"_t2 | as<"user2_name">,
      count() | as<"mutual_count">
    )
    | inner_join<Friendship, "f1"_t2>("user_id"_t1 == "user_id1"_t2)
    | inner_join<User, "u2"_t3>("user_id2"_t2 == "user_id"_t3)
    | inner_join<Friendship, "f2"_t4>("user_id"_t3 == "user_id1"_t4)
    | where("user_id"_t1 < "user_id"_t3)
    | group_by("user_id"_t1, "user_id"_t3)
    | having(count() > 0);

  // Query 2: Users with more than average friends using nested query
  auto friend_count = select_from<User, "u"_t1>(
      "user_id"_t1,
      count("user_id2"_t2) | as<"friend_count">
    )
    | left_join<Friendship, "f"_t2>("user_id"_t1 == "user_id1"_t2)
    | group_by("user_id"_t1);

  auto avg_friend_count = select_from(avg("friend_count"))(conn);

  auto above_avg_query = select_from<User, "u"_t1>(
      "user_id"_t1,
      "username"_t1,
      "friend_count"_t1
    )
    | where("friend_count"_t1 > avg_friend_count)
    | order_by("friend_count"_t1.desc());

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend = select_from<User, "u1"_t1>(
      "username"_t1 | as<"user1_name">,
      "username"_t3 | as<"user2_name">
    )
    | inner_join<Friendship, "f1"_t2>("user_id"_t1 == "user_id1"_t2)
    | inner_join<Friendship, "f2"_t3>("user_id2"_t2 == "user_id1"_t3)
    | inner_join<User, "u2"_t4>("user_id2"_t3 == "user_id"_t4)
    | where("user_id"_t1 != "user_id"_t4)
    | group_by("user_id"_t1, "user_id"_t4);

  // Query 4: Most connected users
  auto most_connected = select_from<User, "u"_t1>(
      "user_id"_t1,
      "username"_t1,
      count("user_id2"_t2) | as<"friend_count">
    )
    | left_join<Friendship, "f"_t2>("user_id"_t1 == "user_id1"_t2)
    | group_by("user_id"_t1)
    | order_by("friend_count"_t1.desc());

  // Query 5: Same city recommendations
  auto recommendations = select_from<User, "u1"_t1>(
      "username"_t1 | as<"user1_name">,
      "username"_t2 | as<"user2_name">
    )
    | inner_join<User, "u2"_t2>("city"_t1 == "city"_t2 && "user_id"_t1 != "user_id"_t2)
    | where(!exists(select_from<Friendship, "f"_t3>(
        where("user_id1"_t3 == "user_id"_t1 && "user_id2"_t3 == "user_id"_t2)
      )))
    | group_by("user_id"_t1, "user_id"_t2);

  // Execute all queries and combine results
  auto mutual_results = mutual_query(conn);
  auto friend_of_friend_results = friend_of_friend(conn);
  auto recommendations_results = recommendations(conn);

  std::vector<FriendConnection> results;
  results.reserve(mutual_results.size() + friend_of_friend_results.size() + recommendations_results.size());

  for (const auto& result : mutual_results) {
    results.push_back({result.user1_name, result.user2_name, result.mutual_count});
  }

  for (const auto& result : friend_of_friend_results) {
    results.push_back({result.user1_name, result.user2_name, 0}); // 0 mutual count for friend-of-friend
  }

  for (const auto& result : recommendations_results) {
    results.push_back({result.user1_name, result.user2_name, 0}); // 0 mutual count for recommendations
  }

  return results;
}

}  // namespace analyze_social_network
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"
2. **Table Creation**: Uses `drop | if_exists | create_table` pattern to safely create tables
3. **SELF-JOIN for Mutual Friends**: Implements complex join with multiple table aliases using `"alias"_tN` syntax
4. **Nested Queries**: Uses subqueries with `exists()` and aggregation functions like `avg()`
5. **Aggregation Functions**: Uses `count()` with proper grouping and having clauses
6. **Query Combination**: Executes multiple queries and combines results into a single vector
7. **Type Safety**: Leverages sqlgen's strong typing system for all operations

The implementation follows sqlgen best practices and uses the library's functional programming style with operator chaining (`|`) for building complex SQL queries in a type-safe manner.

