  static_assert(std::is_same_v<ToType, Nothing>,
                "You cannot call to<...> before a join.");

  if constexpr (std::is_same_v<JoinsType, Nothing>) {
    using NewJoinsType =
        rfl::Tuple<transpilation::Join<OtherTableOrQueryType, ConditionType,
                                       _alias, _how>>;

