          "last_name"_t2 | sqlgen::as<"last_name">,
          "salary"_t2 | sqlgen::as<"salary">,
          "department_name"_t1 | sqlgen::as<"department_name">
        )
        | sqlgen::right_join<Department, "d">("department_id"_t2 == "department_id"_t1)
        | sqlgen::to<std::vector<JoinResult>>;

      auto right_results = right_query(conn);
